Component({
  properties: {
    type: {
      type: Number,
      value: 1
    },
    list: {
      type: Array,
      value: [],
      observer(newVal) {
        const newList = JSON.parse(JSON.stringify(newVal))
        if (newList.length % 2 !== 0) {
          newList.push({})
        }
        const lists = []
        for (let i = 0; i < newList.length; i++) {
          if (i % 2 === 0) {
            lists.push([])
          }
          lists[lists.length - 1].push(newList[i])
        }
        this.setData({
          dealList: lists
        })
      }
    }
  },
  data: {
    dealList: []
  },
  methods: {
    clickItem(e) {
      const item = e.currentTarget.dataset.item
      if (item.id) {
        this.triggerEvent('clickItem', {
          data: {
            type: 'activity',
            id: item.id
          }
        })
      }
    }
  }
})
